      if (err.statusCode) {
        res.status(err.statusCode).json(errorResponse(err.code, err.message));
        return;
      }
      next(err);
    }
  }

  async me(req: AuthenticatedRequest, res: Response, next: NextFunction) {
    try {
      const user = await authService.getCurrentUser(req.user!.userId);
