{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/week-2/HarborOps/TASK-87/repo/backend/src/modules/inventory/inventory.routes.ts", "content": "import { Router, Response, NextFunction } from 'express';
import { authenticate, authorize } from '../../middleware/auth';
import { AuthenticatedRequest, successResponse, paginate } from '../../types';
import prisma from '../../lib/prisma';
import { z } from 'zod';

const router = Router();

// Items CRUD
const createItemSchema = z.object({
  name: z.string().min(1).max(200),
  sku: z.string().min(1).max(100),
  category: z.string().min(1).max(100),
  description: z.string().optional(),
  isLotControlled: z.boolean().default(false),
  unitOfMeasure: z.string().default('EA'),
  unitPrice: z.number().positive().optional(),
});

router.get('/items', authenticate, async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const { page, pageSize, skip, take } = paginate(req.query.page as string, req.query.pageSize as string);
    const category = req.query.category as string | undefined;

    const where: any = { isActive: true };
    if (category) where.category = category;

    const [items, total] = await Promise.all([
      prisma.item.findMany({ where, skip, take, orderBy: { name: 'asc' } }),
      prisma.item.count({ where }),
    ]);
    res.json(successResponse({ items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) }));
  } catch (err) {
    next(err);
  }
});

router.post(
  '/items',
  authenticate,
  authorize('ADMIN', 'MANAGER', 'INVENTORY_CLERK'),
  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    try {
      const input = createItemSchema.parse(req.body);
      const item = await prisma.item.create({ data: input });
      res.status(201).json(successResponse(item));
    } catch (err) {
      next(err);
    }
  }
);

router.get('/items/:id', authenticate, async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const id = parseInt(req.params.id, 10);
    const item = await prisma.item.findUnique({
      where: { id },
      include: {
        stockLevels: { include: { location: true, lot: true } },
        lots: true,
      },
    });
    if (!item) {
      res.status(404).json({ success: false, error: { code: 'NOT_FOUND', message: 'Item not found' } });
      return;
    }
    res.json(successResponse(item));
  } catch (err) {
    next(err);
  }
});

// Vendors
router.get('/vendors', authenticate, async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const vendors = await prisma.vendor.findMany({
      where: { isActive: true },
      select: {
        id: true,
        name: true,
        isActive: true,
        createdAt: true,
        // contactEncrypted hidden from non-admin
        ...(req.user?.role === 'ADMIN' ? { contactEncrypted: true } : {}),
      },
      orderBy: { name: 'asc' },
    });
    res.json(successResponse(vendors));
  } catch (err) {
    next(err);
  }
});

router.post(
  '/vendors',
  authenticate,
  authorize('ADMIN', 'MANAGER'),
  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    try {
      const input = z.object({
        name: z.string().min(1).max(200),
        contactEncrypted: z.string().optional(),
      }).parse(req.body);
      const vendor = await prisma.vendor.create({ data: input });
      res.status(201).json(successResponse(vendor));
    } catch (err) {
      next(err);
    }
  }
);

// Low-stock alerts
router.get('/low-stock', authenticate, async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const stockLevels = await prisma.stockLevel.findMany({
      include: { item: true, location: true, lot: true },
    });

    const alerts = stockLevels.filter((sl) => {
      const avgUsageThreshold = Number(sl.avgDailyUsage) * 7;
      const threshold = Math.max(sl.safetyThreshold, avgUsageThreshold);
      return sl.onHand < threshold;
    });

    res.json(successResponse(alerts));
  } catch (err) {
    next(err);
  }
});

// Ledger (query center)
router.get('/ledger', authenticate, authorize('MANAGER', 'ADMIN'), async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const { page, pageSize, skip, take } = paginate(req.query.page as string, req.query.pageSize as string);

    const where: any = {};
    if (req.query.itemId) where.itemId = parseInt(req.query.itemId as string, 10);
    if (req.query.locationId) {
      const locId = parseInt(req.query.locationId as string, 10);
      where.OR = [{ fromLocationId: locId }, { toLocationId: locId }];
    }
    if (req.query.vendorId) where.vendorId = parseInt(req.query.vendorId as string, 10);
    if (req.query.lotId) where.lotId = parseInt(req.query.lotId as string, 10);
    if (req.query.movementType) where.movementType = req.query.movementType;
    if (req.query.startDate || req.query.endDate) {
      where.createdAt = {};
      if (req.query.startDate) where.createdAt.gte = new Date(req.query.startDate as string);
      if (req.query.endDate) where.createdAt.lte = new Date(req.query.endDate as string);
    }

    const [items, total] = await Promise.all([
      prisma.inventoryLedger.findMany({
        where,
        skip,
        take,
        include: {
          item: { select: { name: true, sku: true } },
          lot: { select: { lotNumber: true } },
          fromLocation: { select: { name: true } },
          toLocation: { select: { name: true } },
          vendor: { select: { name: true } },
          performer: { select: { displayName: true } },
        },
        orderBy: { createdAt: 'desc' },
      }),
      prisma.inventoryLedger.count({ where }),
    ]);

    res.json(successResponse({ items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) }));
  } catch (err) {
    next(err);
  }
});

export default router;
"}

