import { authenticate, authorize } from '../../middleware/auth';
import { AuthenticatedRequest, successResponse, paginate } from '../../types';
import prisma from '../../lib/prisma';
import { cache } from '../../lib/cache';

const router = Router();

router.get('/products', authenticate, async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const { page, pageSize, skip, take } = paginate(req.query.page as string, req.query.pageSize as string);
    const q = (req.query.q as string) || '';
    const category = req.query.category as string | undefined;
    const sortBy = (req.query.sortBy as string) || 'name';
    const sortDir = (req.query.sortDir as string) === 'desc' ? 'desc' : 'asc';

    const cacheKey = `search:${q}:${category}:${sortBy}:${sortDir}:${page}:${pageSize}`;
    const cached = cache.get<any>(cacheKey);
    if (cached) {
      res.json(successResponse(cached));
      return;
    }

    const where: any = { isActive: true };
    if (category) where.category = category;
    if (q) {
      where.OR = [
        { name: { contains: q } },
        { description: { contains: q } },
        { sku: { contains: q } },
      ];
    }

    const orderBy: any = {};
    if (sortBy === 'name') orderBy.name = sortDir;
    else if (sortBy === 'price') orderBy.unitPrice = sortDir;
    else if (sortBy === 'date') orderBy.createdAt = sortDir;
    else orderBy.name = sortDir;

    const [items, total] = await Promise.all([
      prisma.item.findMany({
        where,
        skip,
        take,
        include: { productAttributes: true },
        orderBy,
      }),
      prisma.item.count({ where }),
    ]);

    // Log search
    if (q) {
      await prisma.searchLog.create({
        data: {
          userId: req.user?.userId,
          queryText: q,
          resultsCount: total,
        },
      }).catch(() => {}); // non-critical
    }

    const result = { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
    cache.set(cacheKey, result);
    res.json(successResponse(result));
  } catch (err) {
    next(err);
  }
});

router.get('/suggestions', authenticate, async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const terms = await prisma.suggestedTerm.findMany({
      orderBy: { frequency: 'desc' },
      take: 20,
    });
    res.json(successResponse(terms));
  } catch (err) {
    next(err);
  }
});

router.get(
  '/trending',
  authenticate,
  authorize('MANAGER', 'ADMIN'),
  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    try {
      const terms = await prisma.suggestedTerm.findMany({
        where: { isTrending: true },
        orderBy: { frequency: 'desc' },
        take: 50,
      });
      res.json(successResponse(terms));
    } catch (err) {
      next(err);
    }
  }
);

export default router;
"}

