          </n-breadcrumb-item>
          <n-breadcrumb-item v-if="$route.name !== 'Dashboard'">
            {{ $route.name }}
          </n-breadcrumb-item>
        </n-breadcrumb>
      </n-layout-header>

      <n-layout-content class="p-6" content-style="background: #f5f7fa;">
        <router-view />
      </n-layout-content>
    </n-layout>
  </n-layout>
