<script setup lang="ts">
import { ref, onMounted, h } from 'vue';
import { useRouter } from 'vue-router';
import { NTag } from 'naive-ui';
import apiClient from '../../api/client';

const router = useRouter();
const loading = ref(false);
const loadingAlerts = ref(false);
const stockData = ref<any[]>([]);
const alertData = ref<any[]>([]);
const selectedLocation = ref<string | null>(null);
const selectedCategory = ref<string | null>(null);

const locationOptions = ref<{ label: string; value: string }[]>([]);
const categoryOptions = [
  { label: 'Linens', value: 'Linens' },
  { label: 'Amenities', value: 'Amenities' },
  { label: 'Maintenance', value: 'Maintenance' },
];

const stockColumns = [
  { title: 'Item', key: 'item.name', render: (row: any) => row.item?.name || '-' },
  { title: 'SKU', key: 'item.sku', render: (row: any) => row.item?.sku || '-' },
  { title: 'Location', key: 'location.name', render: (row: any) => row.location?.name || '-' },
  { title: 'On Hand', key: 'onHand' },
  { title: 'Safety Threshold', key: 'safetyThreshold' },
  {
    title: 'Status',
    key: 'status',
    render: (row: any) => {
      const threshold = Math.max(row.safetyThreshold, Number(row.avgDailyUsage) * 7);
      const isLow = row.onHand < threshold;
      return h(NTag, { type: isLow ? 'error' : 'success', size: 'small' }, { default: () => isLow ? 'Low Stock' : 'OK' });
    },
  },
];

const alertColumns = [
  { title: 'Item', key: 'item.name', render: (row: any) => row.item?.name || '-' },
  { title: 'Location', key: 'location.name', render: (row: any) => row.location?.name || '-' },
  { title: 'On Hand', key: 'onHand' },
  { title: 'Threshold', key: 'safetyThreshold' },
  { title: 'Avg Daily Usage', key: 'avgDailyUsage', render: (row: any) => Number(row.avgDailyUsage).toFixed(1) },
];

async function loadLocations() {
  try {
    const res = await apiClient.get('/locations');
    locationOptions.value = res.data.data.map((l: any) => ({ label: l.name, value: String(l.id) }));
  } catch {}
}

async function loadAlerts() {
  loadingAlerts.value = true;
  try {
    const res = await apiClient.get('/inventory/low-stock');
    alertData.value = res.data.data;
  } finally {
    loadingAlerts.value = false;
  }
}

onMounted(async () => {
  await loadLocations();
  await loadAlerts();
});
</script>
"}

