<script setup lang="ts">
import { ref, reactive, onMounted } from 'vue';
import apiClient from '../../api/client';

const loading = ref(false);
const ledgerData = ref<any[]>([]);

const filters = reactive({
  dateRange: null as [number, number] | null,
  locationId: null as string | null,
  itemId: null as string | null,
  vendorId: null as string | null,
  movementType: null as string | null,
});

const pagination = reactive({ page: 1, pageSize: 20, itemCount: 0, pageCount: 1 });

const locationOptions = ref<any[]>([]);
const itemOptions = ref<any[]>([]);
const vendorOptions = ref<any[]>([]);
const movementTypeOptions = [
  { label: 'Receiving', value: 'RECEIVING' },
  { label: 'Issue', value: 'ISSUE' },
  { label: 'Transfer', value: 'TRANSFER' },
  { label: 'Stock Count', value: 'STOCK_COUNT' },
  { label: 'Adjustment', value: 'ADJUSTMENT' },
];

const columns = [
  { title: 'Date', key: 'createdAt', render: (row: any) => new Date(row.createdAt).toLocaleDateString() },
  { title: 'Type', key: 'movementType' },
  { title: 'Item', key: 'item', render: (row: any) => row.item?.name || '-' },
  { title: 'From', key: 'from', render: (row: any) => row.fromLocation?.name || '-' },
  { title: 'To', key: 'to', render: (row: any) => row.toLocation?.name || '-' },
  { title: 'Qty', key: 'quantity' },
  { title: 'Vendor', key: 'vendor', render: (row: any) => row.vendor?.name || '-' },
  { title: 'By', key: 'performer', render: (row: any) => row.performer?.displayName || '-' },
  { title: 'Ref#', key: 'referenceNumber' },
];

async function loadLedger() {
  loading.value = true;
  try {
    const params: any = { page: pagination.page, pageSize: pagination.pageSize };
    if (filters.locationId) params.locationId = filters.locationId;
    if (filters.itemId) params.itemId = filters.itemId;
    if (filters.vendorId) params.vendorId = filters.vendorId;
    if (filters.movementType) params.movementType = filters.movementType;
    if (filters.dateRange) {
      params.startDate = new Date(filters.dateRange[0]).toISOString();
      params.endDate = new Date(filters.dateRange[1]).toISOString();
    }
    const res = await apiClient.get('/inventory/ledger', { params });
    ledgerData.value = res.data.data.items;
    pagination.itemCount = res.data.data.total;
    pagination.pageCount = res.data.data.totalPages;
  } finally {
    loading.value = false;
  }
}

function handlePageChange(page: number) {
  pagination.page = page;
  loadLedger();
}

async function exportData(format: string) {
  // Will be implemented with export endpoint
  window.open(`/api/inventory/ledger/export?format=${format}`, '_blank');
}

onMounted(async () => {
  const [locations, items, vendors] = await Promise.all([
    apiClient.get('/locations'),
    apiClient.get('/inventory/items?pageSize=100'),
    apiClient.get('/inventory/vendors'),
  ]);
  locationOptions.value = locations.data.data.map((l: any) => ({ label: l.name, value: String(l.id) }));
  itemOptions.value = items.data.data.items.map((i: any) => ({ label: i.name, value: String(i.id) }));
  vendorOptions.value = vendors.data.data.map((v: any) => ({ label: v.name, value: String(v.id) }));
  await loadLedger();
});
</script>
"}

