      apiClient.get('/trust/score'),
      apiClient.get('/trust/history'),
    ]);
    trustScore.value = Number(scoreRes.data.data.score);
    creditHistory.value = historyRes.data.data;
  } finally {
    loading.value = false;
  }
});
</script>
"}

