          placeholder="Search products by name, SKU, or description..."
          size="large"
          clearable
          @keyup.enter="search"
          class="flex-1"
        />
        <n-select v-model:value="category" :options="categoryOptions" placeholder="Category" clearable class="w-48" />
        <n-select v-model:value="sortBy" :options="sortOptions" placeholder="Sort by" class="w-40" />
        <n-button type="primary" size="large" @click="search">Search</n-button>
      </div>

      <div v-if="suggestions.length" class="mt-3 flex gap-2 flex-wrap">
        <n-tag v-for="s in suggestions" :key="s.term" size="small" class="cursor-pointer" @click="query = s.term; search()">
          {{ s.term }}
        </n-tag>
      </div>
    </n-card>

    <n-card>
      <n-data-table
        :columns="columns"
        :data="results"
        :loading="loading"
        :pagination="pagination"
        striped
        @update:page="handlePage"
      />
    </n-card>
  </div>
</template>

<script setup lang="ts">
import { ref, reactive, onMounted } from 'vue';
import apiClient from '../../api/client';

const query = ref('');
const category = ref<string | null>(null);
const sortBy = ref('name');
const loading = ref(false);
const results = ref<any[]>([]);
const suggestions = ref<any[]>([]);
const pagination = reactive({ page: 1, pageSize: 20, itemCount: 0 });

const categoryOptions = [
  { label: 'Linens', value: 'Linens' },
  { label: 'Amenities', value: 'Amenities' },
  { label: 'Maintenance', value: 'Maintenance' },
];

const sortOptions = [
  { label: 'Name', value: 'name' },
  { label: 'Price', value: 'price' },
  { label: 'Date', value: 'date' },
];

const columns = [
  { title: 'Name', key: 'name' },
  { title: 'SKU', key: 'sku' },
  { title: 'Category', key: 'category' },
  { title: 'Unit Price', key: 'unitPrice', render: (row: any) => row.unitPrice ? `$${Number(row.unitPrice).toFixed(2)}` : '-' },
  { title: 'Unit', key: 'unitOfMeasure' },
  { title: 'Lot Controlled', key: 'isLotControlled', render: (row: any) => row.isLotControlled ? 'Yes' : 'No' },
];

async function search() {
  loading.value = true;
  try {
    const params: any = { page: pagination.page, pageSize: pagination.pageSize, sortBy: sortBy.value };
    if (query.value) params.q = query.value;
    if (category.value) params.category = category.value;
    const res = await apiClient.get('/search/products', { params });
    results.value = res.data.data.items;
    pagination.itemCount = res.data.data.total;
  } finally {
    loading.value = false;
  }
}

function handlePage(page: number) {
  pagination.page = page;
  search();
}

onMounted(async () => {
  await search();
  try {
    const res = await apiClient.get('/search/suggestions');
    suggestions.value = res.data.data.slice(0, 10);
  } catch {}
});
</script>
"}

