            </n-statistic>
          </n-card>
        </div>
        <n-card title="Daily KPI Trend">
          <n-data-table :columns="kpiColumns" :data="kpiData" :loading="loading" :pagination="{ pageSize: 15 }" striped />
        </n-card>
      </n-tab-pane>

      <n-tab-pane name="review-efficiency" tab="Review Efficiency">
        <n-card>
          <n-data-table :columns="efficiencyColumns" :data="efficiencyData" :loading="loading" :pagination="{ pageSize: 15 }" striped />
        </n-card>
      </n-tab-pane>

      <n-tab-pane name="scheduled" tab="Scheduled Reports">
        <n-card>
          <n-data-table :columns="scheduledColumns" :data="scheduledReports" :loading="loading" :pagination="{ pageSize: 15 }" striped />
        </n-card>
      </n-tab-pane>
    </n-tabs>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted } from 'vue';
import apiClient from '../../api/client';

const loading = ref(false);
const kpiData = ref<any[]>([]);
const efficiencyData = ref<any[]>([]);
const scheduledReports = ref<any[]>([]);

const kpiCards = computed(() => {
  const latest = kpiData.value[0];
  if (!latest) return [
    { label: 'DAU', value: '--', suffix: '' },
    { label: 'Conversion', value: '--', suffix: '%' },
    { label: 'AOV', value: '--', suffix: '' },
    { label: 'Repurchase', value: '--', suffix: '%' },
    { label: 'Refund Rate', value: '--', suffix: '%' },
  ];
  return [
    { label: 'DAU', value: latest.dau, suffix: '' },
    { label: 'Conversion', value: latest.conversionRate, suffix: '%' },
    { label: 'AOV', value: `$${latest.aov}`, suffix: '' },
    { label: 'Repurchase', value: latest.repurchaseRate, suffix: '%' },
    { label: 'Refund Rate', value: latest.refundRate, suffix: '%' },
  ];
});

const kpiColumns = [
  { title: 'Date', key: 'date', render: (row: any) => new Date(row.date).toLocaleDateString() },
  { title: 'DAU', key: 'dau' },
  { title: 'Conversion %', key: 'conversionRate' },
  { title: 'AOV', key: 'aov', render: (row: any) => `$${row.aov}` },
  { title: 'Repurchase %', key: 'repurchaseRate' },
  { title: 'Refund %', key: 'refundRate' },
];

const efficiencyColumns = [
  { title: 'Date', key: 'date', render: (row: any) => new Date(row.date).toLocaleDateString() },
  { title: 'Avg Moderation Time (hrs)', key: 'avgModerationTimeHrs' },
  { title: 'Flagged', key: 'flaggedCount' },
  { title: 'Resolved', key: 'resolvedCount' },
  { title: 'Appeal Rate %', key: 'appealRate' },
];

const scheduledColumns = [
  { title: 'Report Type', key: 'reportType' },
  { title: 'Scheduled Time', key: 'scheduledTime', render: (row: any) => new Date(row.scheduledTime).toLocaleString() },
  { title: 'Status', key: 'status' },
  { title: 'Created', key: 'createdAt', render: (row: any) => new Date(row.createdAt).toLocaleDateString() },
];

onMounted(async () => {
  loading.value = true;
  try {
    const [kpiRes, effRes, schedRes] = await Promise.all([
      apiClient.get('/reports/kpi/dashboard'),
      apiClient.get('/reports/review-efficiency'),
      apiClient.get('/reports/scheduled'),
    ]);
    kpiData.value = kpiRes.data.data;
    efficiencyData.value = effRes.data.data;
    scheduledReports.value = schedRes.data.data;
  } finally {
    loading.value = false;
  }
});
</script>
"}

