<script setup lang="ts">
import { ref, onMounted, h } from 'vue';
import { NTag, NSelect, useMessage } from 'naive-ui';
import apiClient from '../../api/client';

const loading = ref(false);
const users = ref<any[]>([]);
const message = useMessage();

const roleOptions = [
  { label: 'Admin', value: 'ADMIN' },
  { label: 'Manager', value: 'MANAGER' },
  { label: 'Inventory Clerk', value: 'INVENTORY_CLERK' },
  { label: 'Front Desk', value: 'FRONT_DESK' },
  { label: 'Host', value: 'HOST' },
  { label: 'Guest', value: 'GUEST' },
  { label: 'Moderator', value: 'MODERATOR' },
];

async function changeRole(userId: number, role: string) {
  try {
    await apiClient.patch(`/users/${userId}/role`, { role });
    message.success('Role updated');
    await loadUsers();
  } catch (err: any) {
    message.error(err.response?.data?.error?.message || 'Failed to update role');
  }
}

const columns = [
  { title: 'ID', key: 'id', width: 60 },
  { title: 'Username', key: 'username' },
  { title: 'Display Name', key: 'displayName' },
  {
    title: 'Role',
    key: 'role',
    width: 200,
    render: (row: any) =>
      h(NSelect, {
        value: row.role,
        options: roleOptions,
        size: 'small',
        onUpdateValue: (val: string) => changeRole(row.id, val),
      }),
  },
  {
    title: 'Status',
    key: 'isActive',
    render: (row: any) =>
      h(NTag, { type: row.isActive ? 'success' : 'error', size: 'small' }, { default: () => row.isActive ? 'Active' : 'Inactive' }),
  },
  { title: 'Created', key: 'createdAt', render: (row: any) => new Date(row.createdAt).toLocaleDateString() },
];

async function loadUsers() {
  loading.value = true;
  try {
    const res = await apiClient.get('/users');
    users.value = res.data.data.items;
  } finally {
    loading.value = false;
  }
}

onMounted(loadUsers);
</script>
"}

