#!/bin/bash
set -e

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"

echo "========================================"
echo "  HarborOps Test Runner"
echo "========================================"

API_BASE_URL="${API_BASE_URL:-http://localhost:3000}"

# ─── Unit Tests ──────────────────────────────────────────────────
echo ""
