import { Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { config } from '../config';
import { AuthenticatedRequest, JwtPayload, errorResponse } from '../types';
import { Role } from '@prisma/client';

export function authenticate(req: AuthenticatedRequest, res: Response, next: NextFunction): void {
  const header = req.headers.authorization;
  if (!header || !header.startsWith('Bearer ')) {
    res.status(401).json(errorResponse('UNAUTHORIZED', 'Missing or invalid authorization header'));
    return;
  }

  const token = header.slice(7);
  try {
    const payload = jwt.verify(token, config.jwt.secret) as JwtPayload;
    req.user = payload;
    next();
  } catch (err) {
    res.status(401).json(errorResponse('TOKEN_INVALID', 'Invalid or expired token'));
  }
}

export function authorize(...roles: Role[]) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction): void => {
    if (!req.user) {
      res.status(401).json(errorResponse('UNAUTHORIZED', 'Authentication required'));
      return;
    }
    if (roles.length > 0 && !roles.includes(req.user.role)) {
      res.status(403).json(errorResponse('FORBIDDEN', 'Insufficient permissions'));
      return;
    }
    next();
  };
}
```

**errorHandler.ts:**
```typescript
import { Request, Response, NextFunction } from 'express';
import { ZodError } from 'zod';
import { logger } from '../lib/logger';
import { errorResponse } from '../types';

export function errorHandler(err: Error, req: Request, res: Response, _next: NextFunction): void {
  logger.error({ err, path: req.path, method: req.method }, 'Unhandled error');

  if (err instanceof ZodError) {
    res.status(400).json(
      errorResponse('VALIDATION_ERROR', 'Request validation failed', err.errors)
    );
    return;
  }

  if (err.name === 'PrismaClientKnownRequestError') {
    const prismaErr = err as any;
    if (prismaErr.code === 'P2002') {
      res.status(409).json(errorResponse('CONFLICT', 'A record with this value already exists'));
      return;
    }
    if (prismaErr.code === 'P2025') {
      res.status(404).json(errorResponse('NOT_FOUND', 'Record not found'));
      return;
    }
  }

  res.status(500).json(errorResponse('INTERNAL_ERROR', 'An unexpected error occurred'));
}
```

**rateLimiter.ts:**
```typescript
import { Response, NextFunction } from 'express';
import { AuthenticatedRequest, errorResponse } from '../types';
import prisma from '../lib/prisma';
import { config } from '../config';

export function rateLimit(action: string, maxPerHour?: number) {
  const limit = maxPerHour ?? config.rateLimit.reviewsPerHour;

  return async (req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> => {
    if (!req.user) {
      res.status(401).json(errorResponse('UNAUTHORIZED', 'Authentication required'));
      return;
    }

    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
    const count = await prisma.rateLimitLog.count({
      where: {
        userId: req.user.userId,
        action,
        createdAt: { gte: oneHourAgo },
      },
    });

    if (count >= limit) {
      res.status(429).json(
        errorResponse('RATE_LIMITED', `Rate limit exceeded. Maximum ${limit} ${action} actions per hour.`)
      );
      return;
    }

    // Log the action
    await prisma.rateLimitLog.create({
      data: {
        userId: req.user.userId,
        action,
        createdAt: new Date(),
      },
    });

    next();
  };
}
```

**requestLogger.ts:**
