import { Request, Response, NextFunction } from 'express';
import { logger } from '../lib/logger';

export function requestLogger(req: Request, res: Response, next: NextFunction): void {
  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    logger.info(
      {
        method: req.method,
        path: req.path,
        status: res.statusCode,
        duration: `${duration}ms`,
        ip: req.ip,
      },
      `${req.method} ${req.path} ${res.statusCode} ${duration}ms`
    );
  });
  next();
}
```

**upload.ts:**
```typescript
import multer from 'multer';
import path from 'path';
import { v4 as uuidv4 } from 'uuid';
import { config } from '../config';

const storage = multer.diskStorage({
  destination: (_req, _file, cb) => {
    cb(null, config.upload.dir);
  },
  filename: (_req, file, cb) => {
    const ext = path.extname(file.originalname);
    cb(null, `${uuidv4()}${ext}`);
  },
});

const fileFilter = (_req: any, file: Express.Multer.File, cb: multer.FileFilterCallback) => {
  const allowed = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
  if (allowed.includes(file.mimetype)) {
    cb(null, true);
  } else {
    cb(new Error('Invalid file type. Only JPEG, PNG, GIF, and WebP are allowed.'));
  }
};

export const upload = multer({
  storage,
  fileFilter,
  limits: {
    fileSize: config.upload.maxFileSize,
    files: config.upload.maxFiles,
  },
});
```

---

### **SUMMARY OF TESTING PATTERNS**

**Test Response Structure:**
```json
{
  "success": true/false,
  "data": { /* response data */ },
  "error": { "code": "ERROR_CODE", "message": "...", "details": {...} }
}
```

**HTTP Status Codes Used:**
- 200: Success
- 201: Created (registration)
- 400: Validation error
- 401: Unauthorized/Invalid credentials/Missing token
- 403: Forbidden (insufficient permissions)
- 404: Not found
- 409: Conflict (duplicate record)
- 429: Rate limited
- 500: Internal error

**Error Codes:**
- UNAUTHORIZED, TOKEN_INVALID, FORBIDDEN
- VALIDATION_ERROR, CONFLICT, NOT_FOUND, RATE_LIMITED
- INVALID_CREDENTIALS, INTERNAL_ERROR

**Demo User Roles & Credentials:**
- admin / admin123!
- manager / manager123!
- clerk / clerk123!
- frontdesk / frontdesk123!
- host / host123!
- guest / guest123!
- moderator / moderator123!

This infrastructure is ready for expansion with additional test suites following these patterns.

