private generateRefNum(type: 'RCV'|'ISS'|'TRF'|'STC'|'ADJ'): string {
  const date = new Date();
  const yyyymmdd = date.toISOString().slice(0,10).replace(/-/g,'');
  const rand = Math.random().toString(36).slice(2,6).toUpperCase();
  return `${type}-${yyyymmdd}-${rand}`;
}
