Tests are pure logic — no database, no HTTP, no imports from modules that touch Prisma. Use `vi.mock` for dependencies where needed. Pattern mirrors `unit_tests/cache.test.ts` (imports from `../backend/src/...`).

```typescript
import { describe, it, expect } from 'vitest';

// ─── Variance calculation logic ─────────────────────────────────

describe('Inventory - Variance Calculation', () => {
  // Inline the pure formula from inventoryService.finalizeStockCount
  function computeVarianceResult(
    lines: Array<{ systemQty: number; countedQty: number; unitPrice?: number }>
  ) {
    const processed = lines.map(l => {
      const varianceQty = l.countedQty - l.systemQty;
      const variancePct = l.systemQty === 0 ? null : (Math.abs(varianceQty) / l.systemQty) * 100;
      const varianceUsd = l.unitPrice != null ? Math.abs(varianceQty) * l.unitPrice : null;
      return { varianceQty, variancePct, varianceUsd };
    });

    const totalSystemQty = lines.reduce((s, l) => s + l.systemQty, 0);
    const totalAbsVarianceQty = processed.reduce((s, l) => s + Math.abs(l.varianceQty), 0);
    const totalVarianceUsd = processed.reduce((s, l) => s + (l.varianceUsd ?? 0), 0);
    const overallVariancePct = totalSystemQty === 0 ? 0
      : (totalAbsVarianceQty / totalSystemQty) * 100;

    const needsApproval = overallVariancePct > 5 || totalVarianceUsd > 250;
    return { processed, overallVariancePct, totalVarianceUsd, needsApproval };
  }

  it('should compute zero variance when countedQty equals systemQty', () => {
    const result = computeVarianceResult([
      { systemQty: 100, countedQty: 100, unitPrice: 10 },
    ]);
    expect(result.overallVariancePct).toBe(0);
    expect(result.needsApproval).toBe(false);
  });

  it('should flag PENDING_APPROVAL when variancePct exceeds 5%', () => {
    const result = computeVarianceResult([
      { systemQty: 100, countedQty: 90, unitPrice: 1 }, // 10% variance, $10
    ]);
    expect(result.overallVariancePct).toBeCloseTo(10);
    expect(result.needsApproval).toBe(true);
  });

  it('should flag PENDING_APPROVAL when varianceUsd exceeds $250 even if pct is low', () => {
    // 1% variance on expensive item = $300
    const result = computeVarianceResult([
      { systemQty: 1000, countedQty: 990, unitPrice: 30 }, // pct=1%, usd=$300
    ]);
    expect(result.overallVariancePct).toBeCloseTo(1);
    expect(result.totalVarianceUsd).toBe(300);
    expect(result.needsApproval).toBe(true);
  });

  it('should auto-approve when both pct <=5 and usd <=250', () => {
    const result = computeVarianceResult([
      { systemQty: 100, countedQty: 97, unitPrice: 5 }, // pct=3%, usd=$15
    ]);
    expect(result.needsApproval).toBe(false);
  });

  it('should handle null unitPrice as zero USD contribution', () => {
    const result = computeVarianceResult([
      { systemQty: 10, countedQty: 5 }, // no unit price
    ]);
    expect(result.processed[0].varianceUsd).toBeNull();
    expect(result.totalVarianceUsd).toBe(0);
  });
});

// ─── Low-stock threshold formula ────────────────────────────────

describe('Inventory - Low Stock Threshold', () => {
  function isLowStock(onHand: number, safetyThreshold: number, avgDailyUsage: number): boolean {
    const threshold = Math.max(safetyThreshold, avgDailyUsage * 7);
    return onHand < threshold;
  }

  it('uses safetyThreshold when it is higher', () => {
    // safetyThreshold=50, avgDailyUsage=2 (threshold=14), onHand=30
    expect(isLowStock(30, 50, 2)).toBe(true);
  });

  it('uses avgDailyUsage*7 when it is higher', () => {
    // safetyThreshold=10, avgDailyUsage=5 (threshold=35), onHand=20
    expect(isLowStock(20, 10, 5)).toBe(true);
  });

  it('is not low-stock when onHand equals threshold exactly', () => {
    expect(isLowStock(35, 10, 5)).toBe(false);
  });

  it('handles zero avgDailyUsage (falls back to safetyThreshold)', () => {
    expect(isLowStock(5, 10, 0)).toBe(true);
    expect(isLowStock(15, 10, 0)).toBe(false);
  });
});

// ─── Transfer validation ─────────────────────────────────────────

describe('Inventory - Transfer Quantity Validation', () => {
  function validateTransfer(onHand: number, requested: number): { valid: boolean; error?: string } {
    if (requested > onHand) {
      return { valid: false, error: 'INSUFFICIENT_STOCK' };
    }
    return { valid: true };
  }

  it('rejects transfer when requested > onHand', () => {
    expect(validateTransfer(10, 15).valid).toBe(false);
    expect(validateTransfer(10, 15).error).toBe('INSUFFICIENT_STOCK');
  });

  it('allows transfer when requested === onHand', () => {
    expect(validateTransfer(10, 10).valid).toBe(true);
  });

  it('allows transfer when requested < onHand', () => {
    expect(validateTransfer(10, 5).valid).toBe(true);
  });

  it('rejects transfer of zero quantity from zero stock', () => {
    // quantity=0 is blocked by Zod schema (z.number().int().positive()), but guard anyway
    expect(validateTransfer(0, 1).valid).toBe(false);
  });
});
