16	import reviewsRoutes from './modules/reviews/reviews.routes';
17	import trustRoutes from './modules/trust/trust.routes';
18	import moderationRoutes from './modules/moderation/moderation.routes';
19	import promotionsRoutes from './modules/promotions/promotions.routes';
20	import searchRoutes from './modules/search/search.routes';
21	import reportsRoutes from './modules/reports/reports.routes';
22	
23	const app = express();
24	
25	// Global middleware
26	app.use(cors());
27	app.use(express.json({ limit: '10mb' }));
28	app.use(express.urlencoded({ extended: true }));
29	app.use(requestLogger);
30	
31	// Static file serving for uploads
32	app.use('/uploads', express.static(config.upload.dir));
