49	app.use('/api/reviews', reviewsRoutes);
50	app.use('/api/trust', trustRoutes);
51	app.use('/api/moderation', moderationRoutes);
52	app.use('/api/promotions', promotionsRoutes);
53	app.use('/api/search', searchRoutes);
54	app.use('/api/reports', reportsRoutes);
55	
56	// 404 handler
57	app.use((_req, res) => {
58	  res.status(404).json({ success: false, error: { code: 'NOT_FOUND', message: 'Route not found' } });
59	});
60	
61	// Global error handler
62	app.use(errorHandler);
63	
64	// Start server
65	app.listen(config.port, '0.0.0.0', () => {
66	  logger.info({ port: config.port, env: config.nodeEnv }, `HarborOps backend running on port ${config.port}`);
