1	import { config } from '../config';
2	
3	interface CacheEntry<T> {
4	  value: T;
5	  expiresAt: number;
6	}
7	
8	class TTLCache {
9	  private store = new Map<string, CacheEntry<unknown>>();
10	  private defaultTtlMs: number;
11	
12	  constructor(defaultTtlMinutes: number = config.cache.ttlMinutes) {
13	    this.defaultTtlMs = defaultTtlMinutes * 60 * 1000;
14	  }
15	
16	  get<T>(key: string): T | undefined {
17	    const entry = this.store.get(key) as CacheEntry<T> | undefined;
18	    if (!entry) return undefined;
19	    if (Date.now() > entry.expiresAt) {
20	      this.store.delete(key);
21	      return undefined;
22	    }
23	    return entry.value;
24	  }
25	
26	  set<T>(key: string, value: T, ttlMs?: number): void {
27	    const expiresAt = Date.now() + (ttlMs ?? this.defaultTtlMs);
28	    this.store.set(key, { value, expiresAt });
29	  }
30	
31	  delete(key: string): boolean {
32	    return this.store.delete(key);
33	  }
34	
35	  clear(): void {
36	    this.store.clear();
37	  }
38	
39	  has(key: string): boolean {
40	    const val = this.get(key);
41	    return val !== undefined;
42	  }
43	
44	  cleanup(): void {
45	    const now = Date.now();
46	    for (const [key, entry] of this.store.entries()) {
47	      if (now > entry.expiresAt) {
48	        this.store.delete(key);
49	      }
50	    }
51	  }
52	
53	  get size(): number {
54	    this.cleanup();
55	    return this.store.size;
56	  }
57	}
58	
59	export const cache = new TTLCache();
60	export { TTLCache };
