// ─── Credit delta map (mirrors trust.service) ────────────────────────────────

const CREDIT_DELTA: Record<number, number> = {
  5: 2,
  4: 1,
  3: 0,
  2: -1,
  1: -2,
};

function applyDelta(currentScore: number, rating: number): number {
