58	<script setup lang="ts">
59	import { ref, onMounted, h } from 'vue';
60	import { useRouter } from 'vue-router';
61	import { NTag } from 'naive-ui';
62	import apiClient from '../../api/client';
63	
64	const router = useRouter();
65	const loading = ref(false);
66	const loadingAlerts = ref(false);
67	const stockData = ref<any[]>([]);
68	const alertData = ref<any[]>([]);
69	const selectedLocation = ref<string | null>(null);
70	const selectedCategory = ref<string | null>(null);
71	
72	const locationOptions = ref<{ label: string; value: string }[]>([]);
73	const categoryOptions = [
74	  { label: 'Linens', value: 'Linens' },
75	  { label: 'Amenities', value: 'Amenities' },
76	  { label: 'Maintenance', value: 'Maintenance' },
77	];
78	
79	const stockColumns = [
80	  { title: 'Item', key: 'item.name', render: (row: any) => row.item?.name || '-' },
81	  { title: 'SKU', key: 'item.sku', render: (row: any) => row.item?.sku || '-' },
82	  { title: 'Location', key: 'location.name', render: (row: any) => row.location?.name || '-' },
83	  { title: 'On Hand', key: 'onHand' },
84	  { title: 'Safety Threshold', key: 'safetyThreshold' },
85	  {
86	    title: 'Status',
87	    key: 'status',
88	    render: (row: any) => {
89	      const threshold = Math.max(row.safetyThreshold, Number(row.avgDailyUsage) * 7);
90	      const isLow = row.onHand < threshold;
91	      return h(NTag, { type: isLow ? 'error' : 'success', size: 'small' }, { default: () => isLow ? 'Low Stock' : 'OK' });
92	    },
93	  },
94	];
95	
96	const alertColumns = [
97	  { title: 'Item', key: 'item.name', render: (row: any) => row.item?.name || '-' },
98	  { title: 'Location', key: 'location.name', render: (row: any) => row.location?.name || '-' },
99	  { title: 'On Hand', key: 'onHand' },
100	  { title: 'Threshold', key: 'safetyThreshold' },
101	  { title: 'Avg Daily Usage', key: 'avgDailyUsage', render: (row: any) => Number(row.avgDailyUsage).toFixed(1) },
102	];
103	
104	async function loadLocations() {
105	  try {
106	    const res = await apiClient.get('/locations');
107	    locationOptions.value = res.data.data.map((l: any) => ({ label: l.name, value: String(l.id) }));
108	  } catch {}
109	}
110	
111	async function loadAlerts() {
112	  loadingAlerts.value = true;
113	  try {
114	    const res = await apiClient.get('/inventory/low-stock');
115	    alertData.value = res.data.data;
116	  } finally {
117	    loadingAlerts.value = false;
118	  }
119	}
120	
121	onMounted(async () => {
122	  await loadLocations();
123	  await loadAlerts();
124	});
125	</script>
