1	import { Request, Response, NextFunction } from 'express';
2	import { ZodError } from 'zod';
3	import { logger } from '../lib/logger';
4	import { errorResponse } from '../types';
5	
6	export function errorHandler(err: Error, req: Request, res: Response, _next: NextFunction): void {
7	  logger.error({ err, path: req.path, method: req.method }, 'Unhandled error');
8	
9	  if (err instanceof ZodError) {
10	    res.status(400).json(
11	      errorResponse('VALIDATION_ERROR', 'Request validation failed', err.errors)
12	    );
13	    return;
14	  }
15	
16	  if (err.name === 'PrismaClientKnownRequestError') {
17	    const prismaErr = err as any;
18	    if (prismaErr.code === 'P2002') {
19	      res.status(409).json(errorResponse('CONFLICT', 'A record with this value already exists'));
20	      return;
21	    }
22	    if (prismaErr.code === 'P2025') {
23	      res.status(404).json(errorResponse('NOT_FOUND', 'Record not found'));
24	      return;
25	    }
26	  }
27	
28	  res.status(500).json(errorResponse('INTERNAL_ERROR', 'An unexpected error occurred'));
29	}
