2	import { logger } from './logger';
3	
4	interface ScheduledJob {
5	  name: string;
6	  schedule: string;
7	  task: () => Promise<void>;
8	}
9	
10	const jobs: ScheduledJob[] = [];
11	
12	export function registerJob(name: string, schedule: string, task: () => Promise<void>): void {
13	  jobs.push({ name, schedule, task });
14	}
15	
16	export function startScheduler(): void {
17	  for (const job of jobs) {
18	    cron.schedule(job.schedule, async () => {
19	      logger.info({ job: job.name }, `Running scheduled job: ${job.name}`);
20	      try {
21	        await job.task();
