1	import prisma from './prisma';
2	import { cache } from './cache';
3	
4	const CACHE_KEY = 'sensitive_words';
5	
6	export async function loadSensitiveWords(): Promise<string[]> {
7	  const cached = cache.get<string[]>(CACHE_KEY);
8	  if (cached) return cached;
9	
10	  const words = await prisma.sensitiveWord.findMany();
11	  const wordList = words.map((w) => w.word.toLowerCase());
12	  cache.set(CACHE_KEY, wordList, 30 * 60 * 1000); // 30 min cache
13	  return wordList;
14	}
15	
16	export async function filterContent(text: string): Promise<{ clean: boolean; flaggedWords: string[] }> {
17	  const sensitiveWords = await loadSensitiveWords();
18	  const normalized = text.toLowerCase().replace(/[^a-z0-9\s]/g, '');
19	  const flaggedWords: string[] = [];
20	
21	  for (const word of sensitiveWords) {
22	    if (normalized.includes(word.toLowerCase())) {
23	      flaggedWords.push(word);
24	    }
25	  }
26	
27	  return {
28	    clean: flaggedWords.length === 0,
29	    flaggedWords,
30	  };
31	}
