1	import prisma from '../../lib/prisma';
2	import { logger } from '../../lib/logger';
3	import { RateTaskInput, AdminAdjustInput } from './trust.schema';
4	
5	function businessError(code: string, message: string, statusCode: number): never {
6	  throw Object.assign(new Error(message), { statusCode, code });
7	}
8	
9	// Credit delta map: rating → credit change
10	const CREDIT_DELTA: Record<number, number> = {
11	  5: 2,
12	  4: 1,
13	  3: 0,
14	  2: -1,
15	  1: -2,
16	};
17	
18	function buildExplanation(rating: number, delta: number, taskId: number): string {
19	  if (delta > 0) return `Received ${rating}★ rating on task #${taskId}: +${delta} trust credit`;
20	  if (delta < 0) return `Received ${rating}★ rating on task #${taskId}: ${delta} trust credit`;
21	  return `Received ${rating}★ rating on task #${taskId}: no trust change`;
22	}
23	
24	export class TrustService {
25	  async getScore(userId: number) {
26	    const score = await prisma.trustScore.findUnique({ where: { userId } });
27	    return score ?? { userId, score: 50 };
28	  }
29	
30	  async getHistory(userId: number, page: number, pageSize: number) {
31	    const skip = (page - 1) * pageSize;
32	    const [items, total] = await Promise.all([
33	      prisma.creditHistory.findMany({
34	        where: { userId },
35	        orderBy: { createdAt: 'desc' },
36	        skip,
37	        take: pageSize,
38	      }),
39	      prisma.creditHistory.count({ where: { userId } }),
40	    ]);
41	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
42	  }
43	
44	  async rateTask(input: RateTaskInput, raterId: number) {
45	    // Prevent self-rating
46	    if (input.rateeId === raterId) {
47	      businessError('SELF_RATING', 'Cannot rate yourself', 422);
48	    }
49	
50	    // Unique per rater+task
51	    const existing = await prisma.taskRating.findUnique({
52	      where: { raterId_taskId: { raterId, taskId: input.taskId } },
53	    });
54	    if (existing) businessError('DUPLICATE', 'You have already rated this task', 409);
55	
56	    // Verify ratee exists
57	    const ratee = await prisma.user.findUnique({ where: { id: input.rateeId } });
58	    if (!ratee) businessError('NOT_FOUND', 'Ratee user not found', 404);
59	
60	    const delta = CREDIT_DELTA[input.rating] ?? 0;
61	    const explanation = buildExplanation(input.rating, delta, input.taskId);
62	
63	    await prisma.$transaction(async (tx) => {
64	      // Create rating record
65	      await tx.taskRating.create({
66	        data: {
67	          raterId,
68	          rateeId: input.rateeId,
69	          taskId: input.taskId,
70	          rating: input.rating,
71	          comment: input.comment ?? null,
72	        },
73	      });
74	
75	      if (delta !== 0) {
76	        // Upsert trust score, clamp 0-100
77	        const current = await tx.trustScore.findUnique({ where: { userId: input.rateeId } });
78	        const currentScore = Number(current?.score ?? 50);
79	        const newScore = Math.max(0, Math.min(100, currentScore + delta));
80	
81	        await tx.trustScore.upsert({
82	          where: { userId: input.rateeId },
83	          create: { userId: input.rateeId, score: newScore, lastUpdated: new Date() },
84	          update: { score: newScore, lastUpdated: new Date() },
85	        });
86	
87	        // Credit history
88	        await tx.creditHistory.create({
89	          data: {
90	            userId: input.rateeId,
91	            changeAmount: delta,
92	            reason: `Task rating from user #${raterId}`,
93	            sourceType: 'TASK_RATING',
94	            sourceId: input.taskId,
95	            explanation,
96	          },
97	        });
98	      }
99	    });
100	
101	    logger.info({ raterId, rateeId: input.rateeId, taskId: input.taskId, rating: input.rating }, 'Task rated');
102	    return { message: 'Rating submitted', delta, explanation };
103	  }
104	
105	  async adminAdjust(input: AdminAdjustInput, adminId: number) {
106	    const user = await prisma.user.findUnique({ where: { id: input.userId } });
107	    if (!user) businessError('NOT_FOUND', 'User not found', 404);
108	
109	    const current = await prisma.trustScore.findUnique({ where: { userId: input.userId } });
110	    const currentScore = Number(current?.score ?? 50);
111	    const newScore = Math.max(0, Math.min(100, currentScore + input.changeAmount));
112	
113	    await prisma.$transaction(async (tx) => {
114	      await tx.trustScore.upsert({
115	        where: { userId: input.userId },
116	        create: { userId: input.userId, score: newScore, lastUpdated: new Date() },
117	        update: { score: newScore, lastUpdated: new Date() },
118	      });
119	
120	      const direction = input.changeAmount > 0 ? `+${input.changeAmount}` : `${input.changeAmount}`;
121	      await tx.creditHistory.create({
122	        data: {
123	          userId: input.userId,
124	          changeAmount: input.changeAmount,
125	          reason: input.reason,
126	          sourceType: 'ADMIN_ADJUSTMENT',
127	          sourceId: adminId,
128	          explanation: `Admin adjustment by #${adminId}: ${direction} (${input.reason})`,
129	        },
130	      });
131	    });
132	
133	    logger.info({ adminId, targetUserId: input.userId, changeAmount: input.changeAmount }, 'Trust score adjusted by admin');
134	    return { userId: input.userId, previousScore: currentScore, newScore };
135	  }
136	}
137	
138	export const trustService = new TrustService();
